<script setup>
import { computed, onMounted, ref } from 'vue'
import axios from 'axios'
// import {
//   Sidebar,
//   SidebarContent,
//   SidebarFooter,
//   SidebarGroup,
//   SidebarGroupContent,
//   SidebarGroupLabel,
//   SidebarHeader,
//   SidebarInset,
//   SidebarMenu,
//   SidebarMenuButton,
//   SidebarMenuItem,
//   SidebarProvider,
//   SidebarRail,
//   SidebarTrigger,
// } from '@/components/ui/sidebar'

const keyword = ref('')
const loading = ref(false)
const loadingConfig = ref(false)
const error = ref('')
const results = ref([])
const spotlight = ref([])
const categories = ref([])
const config = ref({})

const hasResults = computed(() => results.value.length > 0)

const formatPrice = (value) => {
  if (value === null || value === undefined || value === '') return '-'
  return 'Rp ' + Number(value).toLocaleString('id-ID')
}

const loadConfig = async () => {
  loadingConfig.value = true
  try {
    const response = await axios.get('/api/domain/config')

    config.value = response.data.config ?? {}
    categories.value = response.data.categories ?? []

    const spotlightRaw = response.data.config?.SEARCH_DOMAIN_SPOTLIGHT
      ?? response.data.config?.search_domain_spotlight
      ?? []

    if (Array.isArray(spotlightRaw)) {
      spotlight.value = spotlightRaw
    } else {
      spotlight.value = ['.com', '.id', '.co.id', '.my.id', '.net']
    }
  } catch (err) {
    console.error('Load config error:', err)
    spotlight.value = ['.com', '.id', '.co.id', '.my.id', '.net']
  } finally {
    loadingConfig.value = false
  }
}

const searchDomain = async () => {
  error.value = ''
  results.value = []

  if (!keyword.value.trim()) {
    error.value = 'Masukkan nama domain terlebih dahulu.'
    return
  }

  loading.value = true

  try {
    const response = await axios.post('/api/domain/check', {
      keyword: keyword.value.trim(),
    })

    if (Array.isArray(response.data)) {
      results.value = response.data
    } else {
      results.value = response.data.results ?? []
    }
  } catch (err) {
    console.error('Search error:', err)
    error.value = 'Terjadi kesalahan saat mencari domain.'
  } finally {
    loading.value = false
  }
}

const useSpotlight = (ext) => {
  const clean = String(ext).replace(/^\./, '')
  keyword.value = keyword.value.trim()
  if (!keyword.value) {
    error.value = 'Masukkan nama domain terlebih dahulu.'
    return
  }

  results.value = [
    {
      domain: `${keyword.value}.${clean}`,
      available: null,
      register_price: null,
      gimmick_price: null,
      categories: [],
    },
  ]

  searchDomain()
}

onMounted(() => {
  loadConfig()
})
</script>

